--
-- Name: volunteer_list_mv; Type: MATERIALIZED VIEW; Schema: public; Owner: n4d
--

CREATE MATERIALIZED VIEW public.volunteer_list_mv AS
 WITH aggregatedtimeslots AS (
         SELECT d_1.id AS deal_id,
            array_agg(DISTINCT "substring"((t.rrule)::text, 'BYDAY=([A-Z,]+)'::text)) FILTER (WHERE (t.rrule IS NOT NULL)) AS available_days_array_raw,
            array_agg(DISTINCT
                CASE
                    WHEN ((EXTRACT(hour FROM t.start) >= (8)::numeric) AND (EXTRACT(hour FROM t."end") <= (11)::numeric)) THEN '08-11'::text
                    WHEN ((EXTRACT(hour FROM t.start) >= (11)::numeric) AND (EXTRACT(hour FROM t."end") <= (14)::numeric)) THEN '11-14'::text
                    WHEN ((EXTRACT(hour FROM t."end") <= (17)::numeric) AND (EXTRACT(hour FROM t.start) >= (14)::numeric)) THEN '14-17'::text
                    WHEN ((EXTRACT(hour FROM t."end") <= (20)::numeric) AND (EXTRACT(hour FROM t.start) >= (17)::numeric)) THEN '17-20'::text
                    ELSE NULL::text
                END) FILTER (WHERE (t.rrule IS NOT NULL)) AS available_times_array,
            array_agg(DISTINCT t.occasional) FILTER (WHERE (t.occasional IS NOT NULL)) AS available_occasional_array,
            jsonb_agg(jsonb_build_object('start_hour', EXTRACT(hour FROM t.start), 'end_hour', EXTRACT(hour FROM t."end"), 'byday_part', COALESCE("substring"((t.rrule)::text, 'BYDAY=([A-Z,]+)'::text), ''::text), 'occasional', t.occasional)) AS timeslot_data
           FROM (((public.timeslot t
             JOIN public.time_timeslot tt ON ((t.id = tt.timeslot_id)))
             JOIN public."time" tm ON ((tt.time_id = tm.id)))
             JOIN public.deal d_1 ON ((tm.id = d_1.time_id)))
          GROUP BY d_1.id
        ), aggregatedlanguages AS (
         SELECT d_1.id AS deal_id,
            array_agg(lang.id) AS language_ids,
            array_agg(lang.title) AS language_titles
           FROM (((public.language lang
             JOIN public.profile_language pl ON ((lang.id = pl.language_id)))
             JOIN public.profile p_1 ON ((pl.profile_id = p_1.id)))
             JOIN public.deal d_1 ON ((p_1.id = d_1.profile_id)))
          GROUP BY d_1.id
        ), aggregateddistricts AS (
         SELECT d_1.id AS deal_id,
            array_agg(dist.id) AS district_ids,
            array_agg(dist.title) AS district_titles
           FROM (((public.district dist
             JOIN public.location_district ld ON ((dist.id = ld.district_id)))
             JOIN public.location l_1 ON ((ld.location_id = l_1.id)))
             JOIN public.deal d_1 ON ((l_1.id = d_1.location_id)))
          GROUP BY d_1.id
        ), aggregatedactivities AS (
         SELECT d_1.id AS deal_id,
            array_agg(a.id) AS activity_ids,
            array_agg(a.title) AS activity_titles
           FROM (((public.activity a
             JOIN public.profile_activity pa ON ((a.id = pa.activity_id)))
             JOIN public.profile p_1 ON ((pa.profile_id = p_1.id)))
             JOIN public.deal d_1 ON ((p_1.id = d_1.profile_id)))
          GROUP BY d_1.id
        )
 SELECT v.id AS volunteer_id,
    d.id AS deal_id,
    v.status_engagement,
    v.status_type,
    per.first_name,
    per.last_name,
    per.email,
    per.phone,
    per.avatar_url,
    concat_ws(' '::text, NULLIF(TRIM(BOTH FROM per.first_name), ''::text), NULLIF(TRIM(BOTH FROM per.last_name), ''::text)) AS full_name,
    ad.district_ids AS district_ids_array,
    al.language_ids AS language_ids_array,
    (al.language_ids @> ARRAY[( SELECT language.id
           FROM public.language
          WHERE ((language.iso_code)::text = 'de'::text)
         LIMIT 1)]) AS has_german_language,
    ( SELECT array_agg(x.x) AS array_agg
           FROM unnest(at.available_days_array_raw) x(x)) AS available_days_array,
    at.available_times_array,
    at.available_occasional_array,
    aa.activity_titles,
    al.language_titles,
    ad.district_titles,
    at.timeslot_data
   FROM ((((((((public.deal d
     JOIN public.volunteer v ON ((d.id = v.deal_id)))
     JOIN public.person per ON ((v.person_id = per.id)))
     JOIN public.profile p ON ((d.profile_id = p.id)))
     JOIN public.location l ON ((d.location_id = l.id)))
     LEFT JOIN aggregatedactivities aa ON ((d.id = aa.deal_id)))
     LEFT JOIN aggregatedlanguages al ON ((d.id = al.deal_id)))
     LEFT JOIN aggregatedtimeslots at ON ((d.id = at.deal_id)))
     LEFT JOIN aggregateddistricts ad ON ((d.id = ad.deal_id)))
  WHERE (d.type = 'volunteer'::public.deal_type_enum)
  WITH NO DATA;


ALTER MATERIALIZED VIEW public.volunteer_list_mv OWNER TO n4d;

